// VpnManagedTransparentProxyOnDemandRulesElementActionParameter is the ActionParameter dictionary.
// A dictionary that provides rules similar to the OnDemandRules dictionary, but evaluated on each
// connection instead of when the network changes. These dictionaries are evaluated in order, and
// the behavior is determined by the first dictionary that matches.
type VpnManagedTransparentProxyOnDemandRulesElementActionParameter struct {
	// The domains to apply this evaluation.
	Domains []string `plist:"Domains" json:"Domains"`
	// Defines the VPN behavior for the specified domains. Allowed values are:
	DomainAction VpnManagedTransparentProxyOnDemandRulesElementActionParameterDomainAction `plist:"DomainAction" json:"DomainAction"`
	// An array of IP addresses of DNS servers to use for resolving the specified domains. These
	// servers don't need to be part of the device's current network configuration. If these DNS
	// servers aren't reachable, the system establishes a VPN connection. These DNS servers need to be
	// either internal DNS servers or trusted external DNS servers.
	RequiredDNSServers []string `plist:"RequiredDNSServers,omitempty" json:"RequiredDNSServers,omitempty"`
	// An HTTP or HTTPS (preferred) URL to probe, using a GET request. If the URL's hostname can't be
	// resolved, if the server is unreachable, or if the server doesn't respond with a 200 HTTP status
	// code, a VPN connection is established in response.
	RequiredURLStringProbe *string `plist:"RequiredURLStringProbe,omitempty" json:"RequiredURLStringProbe,omitempty"`
}

// VpnManagedTransparentProxyOnDemandRulesElement is the OnDemandRulesElement dictionary.
type VpnManagedTransparentProxyOnDemandRulesElement struct {
	// The action to take if this dictionary matches the current network. Possible values are:
	Action VpnManagedTransparentProxyOnDemandRulesElementAction `plist:"Action" json:"Action"`
	// An array of dictionaries that provides rules similar to the `OnDemandRules` dictionary, but
	// evaluated on each connection instead of when the network changes. This value is only for use
	// with dictionaries in which the `Action` value is `EvaluateConnection`. The system evaluates
	// these dictionaries in order and the first dictionary that matches determines the behavior. Not
	// available in watchOS.
	ActionParameters []VpnManagedTransparentProxyOnDemandRulesElementActionParameter `plist:"ActionParameters,omitempty" json:"ActionParameters,omitempty"`
	// An array of domain names. This rule matches if any of the domain names in the specified list
	// matches any domain in the device's search domains list.
	DNSDomainMatch []string `plist:"DNSDomainMatch,omitempty" json:"DNSDomainMatch,omitempty"`
	// An array of IP addresses. This rule matches if any of the network's specified DNS servers match
	// any entry in the array.
	DNSServerAddressMatch []string `plist:"DNSServerAddressMatch,omitempty" json:"DNSServerAddressMatch,omitempty"`
	// An interface type. If specified, this rule matches only if the primary network interface
	// hardware matches the specified type.
	InterfaceTypeMatch *VpnManagedTransparentProxyOnDemandRulesElementInterfaceTypeMatch `plist:"InterfaceTypeMatch,omitempty" json:"InterfaceTypeMatch,omitempty"`
	// An array of SSIDs to match against the current network. If the network isn't a Wi-Fi network or
	// if the SSID doesn't appear in this array, the match fails.
	SSIDMatch []string `plist:"SSIDMatch,omitempty" json:"SSIDMatch,omitempty"`
	// A URL to probe. This rule matches when this URL is successfully fetched (returns a `200` HTTP
	// status code) without redirection. Not available in watchOS.
	URLStringProbe *string `plist:"URLStringProbe,omitempty" json:"URLStringProbe,omitempty"`
}

// VpnManagedTransparentProxy is the TransparentProxy dictionary.
